import React from "react";
import { useLocation } from "react-router";

// @ts-ignore - virtual module generated by access control plugin
import { pluginPages } from "virtual:xyd-plugin-pages";

/**
 * Renders a plugin-registered custom page.
 * Components are imported via virtual module so they work on both server and client.
 */
export default function PluginPage() {
    const location = useLocation();
    const PageComponent = pluginPages[location.pathname];

    if (!PageComponent) {
        return (
            <div style={{ padding: "48px 24px", textAlign: "center", color: "var(--dark48, #6e6e80)" }}>
                Page not found.
            </div>
        );
    }

    return <PageComponent />;
}
